// Validar datos de entrada y convertir a binario
const data = $input.first().json.body || {};

if (!data.user_id || !data.image_base64) {
  throw new Error('Faltan campos requeridos: user_id, image_base64');
}

return [{
  binary: {
    data: {
      data: data.image_base64,
      mimeType: 'image/jpeg',
      fileName: `factura_${Date.now()}.jpg`
    }
  },
  json: {
    user_id: data.user_id,
    timestamp: new Date().toISOString()
  }
}];

// Pasamos el JSON y el archivo binario intacto al siguiente nodo
return [{
  json: {
    ...$input.first().json,
    storage_path: $node["Subir a Supabase Storage"]?.json?.path || ""
  },
  binary: $input.first().binary
}];

// La IA devuelve markdown, hay que extraer solo el objeto JSON
const rawText = $input.first().json.text || '';
let cleanText = rawText.replace(/```json/gi, '').replace(/```/gi, '').trim();

try {
  const parsed = JSON.parse(cleanText);

  // Normalizar fecha si viene en DD/MM/YYYY
  if (parsed.document_info && parsed.document_info.fecha_emision) {
    const partes = parsed.document_info.fecha_emision.split('/');
    if (partes.length === 3) {
      parsed.document_info.fecha_emision = `${partes[2]}-${partes[1]}-${partes[0]}`;
    }
  }

  return [{ 
    json: {
      ...parsed, 
      monto: parsed.totals?.total || 0,
      proveedor: parsed.supplier?.razon_social || 'Desconocido',
      fecha_factura: parsed.document_info?.fecha_emision || new Date().toISOString().split('T')[0],
      concepto_ocr: parsed.categoria_compra || parsed.concepto_ocr || 'Gasto registrado'
    } 
  }];
} catch (e) {
  throw new Error('La IA no devolvió un JSON válido: ' + cleanText);
}

const ocrData = $node["Parsear JSON OCR"].json;
return [{
  json: {
    success: true,
    extracted: {
      ...ocrData
    },
    message: 'Factura procesada con éxito'
  }
}];
